\begin {aligned}
  {\mathopen {}\left ({\mathopen {}\left (N\cdot  M\right )\mathclose {}}\cdot  L\right )\mathclose {}}_{a,b}
  &=
  \bigoplus _{c\in  {\mathopen {}\left  [l\right  ]\mathclose {}}}
  L_{a,c}\cdot  {\mathopen {}\left (N\cdot  M\right )\mathclose {}}_{c,b}
  \\
  &=
  \bigoplus _{c\in {\mathopen {}\left  [l\right  ]\mathclose {}}}
  L_{a,c}\cdot  \bigoplus _{d\in {\mathopen {}\left  [m\right  ]\mathclose {}}} M_{c,d}\cdot  N_{d,b}
  \\
  &=
  \bigoplus _{c\in {\mathopen {}\left  [l\right  ]\mathclose {}}}
  \bigoplus _{d\in {\mathopen {}\left  [m\right  ]\mathclose {}}}
  L_{a,c}\cdot  M_{c,d}\cdot  N_{d,b}
  \\
  &=
  \bigoplus _{d\in {\mathopen {}\left  [m\right  ]\mathclose {}}}
  {\mathopen {}\left (\bigoplus _{c\in {\mathopen {}\left  [l\right  ]\mathclose {}}} L_{a,c}\cdot  M_{c,d}\right )\mathclose {}}\cdot  N_{d,b}
  \\
  &=
  \bigoplus _{d\in {\mathopen {}\left  [m\right  ]\mathclose {}}}
  {\mathopen {}\left (M\cdot  L\right )\mathclose {}}_{a,d}\cdot  N_{d,b}
  \\
  &=
  N\cdot  {\mathopen {}\left (M\cdot  L\right )\mathclose {}}
\end {aligned}

\begin {aligned}
